from zeep import Client

# Initialize the client with the WSDL URL of the third-party insurance service
client = Client('https://thirdpartyinsurance.com/service?wsdl')

def fetch_insurance_quote():
    policy_number = input("Enter policy number: ")
    customer_name = input("Enter customer name: ")

    # Define the SOAP request parameters
    soap_request = {
        'policyNumber': policy_number,
        'customerName': customer_name
    }

    # Call the service method with the user-provided inputs
    response = client.service.getQuote(**soap_request)

    # Print or process the response as needed
    print("Insurance Quote:", response)

if __name__ == "__main__":
    fetch_insurance_quote()